frame_eqs:
// timed sidon sensor
// le = signal level; desired average value = 2
le=1.4*bass_att+.1*bass+.5*treb;
pulse=above(le,th);
// pulsefreq = running average of interval between last 5 pulses
pulsefreq=if(equal(pulsefreq,0),2,
if(pulse,.8*pulsefreq+.2*(time-lastpulse),pulsefreq));
lastpulse=if(pulse,time,lastpulse);
// bt = relative time; 0 = prev beat; 1 = expected beat
bt=(time-lastbeat)/(.5*beatfreq+.5*pulsefreq);
// hccp = handcicap for th driven by bt
hccp=(.03/(bt+.2))+.5*if(band(above(bt,.8),below(bt,1.2)),
(pow(sin((bt-1)*7.854),4)-1),0);
beat=band(above(le,th+hccp),btblock);
btblock=1-above(le,th+hccp);
lastbeat=if(beat,time,lastbeat);
beatfreq=if(equal(beatfreq,0),2,
if(beat,.8*beatfreq+.2*(time-lastbeat),beatfreq));
// th = threshold
th=if(above(le,th),le+114/(le+10)-7.407,
th+th*.07/(th-12)+below(th,2.7)*.1*(2.7-th));
th=if(above(th,6),6,th);

q8=10/fps;
ccl=ccl+beat;
minorccl=minorccl+q8*le;

q5=ccl+.0032*minorccl;
q6=ccl;

ccx=if(beat,.5+.2*sin(int(rand(354))),ccx);
cx=ccx+.1*sin(.01*minorccl);
q1=ccx;
ccy=if(beat,.5+.2*sin(int(rand(354))),ccy);
cy=ccx+.1*sin(.013*minorccl);
q2=ccy;
q3=4/th;
q4=.01*minorccl;
q7=th;

decay=1-q8*.02;
monitor=decay;


wx=if(pulse,int(rand(10))*.1,wx);
wave_x=wx;
wy=if(pulse,int(rand(10))*.1,wy);
wave_y=wy;
wm=if(pulse,int(rand(20))*.1-1,wm);
wave_mystery=wm;

mv_r=.5+.2*sin(q5)+.3*sin(q5*36.2);
mv_g=.5+.2*sin(q5+2.09)+.3*sin(q5*38.7);
mv_b=.5+.2*sin(q5+4.18)+.3*sin(q5*37.4);
wave_r=.5+.5*sin(q5*36.2);
wave_g=.5+.5*sin(q5*38.7);
wave_b=.5+.5*sin(q5*37.4);

pixel_eqs:
// coordinates transfomation
// q1,q2 = position; q3 = 1/zoom; q4 = rotation
aang=atan2(y-q2,x-q1)+q4;
arad=sqrt(sqr(y-q2)+sqr(x-q1))*q3;

radsector=(arad*4)%3;
angsector=(aang*1.273)%8;

zoom=1+q8*.1*sin(14*(angsector%4)*q6+radsector*q5);
rot=.1*q8*sin(q7)*sin(1.3*angsector*q5+2.7*radsector*q6);

wave_0_per_point:
n=sample*6.283;
phs=-sample * 0.2;
tm=q1 + phs;

flip=flip+1;
flip=flip*below(flip,2);

xp=0;
yp=flip*0.1 + (sin(tm)*0.5 + 0.5)*0.2;
zp=0;

//wrist movement;
ang=sin(tm*2 )*0.5 +0.5;

xq=xp;
sinang=sin(ang);cosang=cos(ang);
yq=yp*sinang + zp*cosang;
zq=yp*cosang - zp*sinang;
yq=yp;
zq=zp;

ang=tm*8;
sinang=sin(ang);cosang=cos(ang);
xp=xq*sinang + yq*cosang;
yp=xq*cosang - yq*sinang;
zp=zq;

//forearm movement;
zp=zp-0.3;
ang=3.14 + sin(tm*2 - 0.5)*1.5;
sinang=sin(ang);cosang=cos(ang);
xq=xp;
yq=yp*sinang + zp*cosang;
zq=yp*cosang - zp*sinang;

//upper arm twist
ang=-1.0 + cos(tm*3.1 + 0.5);
sinang=sin(ang);cosang=cos(ang);
xp=xq*sinang + yq*cosang;
yp=xq*cosang - yq*sinang;
zp=zq;

//upper arm outward;
zp=zp-0.35;
ang=cos(tm*2.3)*1.75 - 1.05;
sinang=sin(ang);cosang=cos(ang);
xq=xp*sinang + zp*cosang;
yq=yp;
zq=xp*cosang - zp*sinang;

//upper arm up down;
ang=cos(tm)*0.5 - 0.5;
sinang=sin(ang);cosang=cos(ang);
xp=xq;
yp=yq*cosang - zq*sinang;
zp=yq*sinang + zq*cosang;

//xp=xq;yp=yq;zp=zq;


//project into screenspace and draw on screen
zp=zp+2;
xs=xp/zp;
ys=yp/zp;

x=xs+0.5;
y=ys*1.3+0.5;


a=if( equal(q8,1) , (1-sample) , sample);
a=a*a;

b=b+pow(1-sample,2)*0.3;



r1=t1;
g1=t2;
b1=t3;
r2=t4;
g2=t5;
b2=t6;

r=r1*flip + r2*(1-flip);
g=g1*flip + g2*(1-flip);
b=b1*flip + b2*(1-flip);

